<?php namespace App\Repositories\Payroll;use App\Repositories\BaseRepository;use App\Models\Payroll\SalaryStructure;use Illuminate\Database\Eloquent\Collection;class SalaryStructureRepository extends BaseRepository{    public function __construct(SalaryStructure $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByEmployee(int $employeeId): ?SalaryStructure    {        return $this->query()->where('employee_id', $employeeId)->first();    }    public function findByDesignation(int $designationId): Collection    {        return $this->findByField('designation_id', $designationId);    }    public function getActiveStructures(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function searchStructures(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->get();    }    public function getBySalaryRange(float $min, float $max): Collection    {        return $this->query()->whereBetween('basic_salary', [$min, $max])->get();    }    public function findByEmployeeAndDesignation(int $employeeId, int $designationId): ?SalaryStructure    {        return $this->query()->where('employee_id', $employeeId)->where('designation_id', $designationId)->first();    }}